import{_ as r,a as t,b as o}from"./chunks/0_H84UsJVgH3V5j96h.14oI3MBq.js";import{_ as i,c as a,o as n,ag as s}from"./chunks/framework.S-Qvb3wi.js";const w=JSON.parse('{"title":"AI Arena","description":"","frontmatter":{},"headers":[],"relativePath":"AI-Arena.md","filePath":"AI-Arena.md"}'),l={name:"AI-Arena.md"};function d(h,e,u,p,c,g){return n(),a("div",null,e[0]||(e[0]=[s('<h1 id="ai-arena" tabindex="-1">AI Arena <a class="header-anchor" href="#ai-arena" aria-label="Permalink to &quot;AI Arena&quot;">​</a></h1><p><strong>DGrid AI Arena</strong> is a dedicated hub inside the DGrid platform where users help evaluate and improve DGrid’s AI models — and earn on‑chain rewards for their contributions.</p><p>By completing simple daily “AI Battles” and inviting new users, participants:</p><ul><li>Compare real AI model responses and signal which are better</li><li>Earn points for each decision and referral</li><li>Convert points into <strong>USDT</strong></li><li>Compete on a <strong>weekly leaderboard</strong> for a shared prize pool</li></ul><p>DGrid AI Arena is not just a gamified layer. It is a core component of DGrid’s AI infrastructure that uses community judgment to:</p><ul><li>Evaluate model quality</li><li>Guide model optimization and deployment</li><li>Continuously align DGrid AI with real user expectations</li></ul><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><h4 id="ai-arena-1" tabindex="-1">AI Arena <a class="header-anchor" href="#ai-arena-1" aria-label="Permalink to &quot;AI Arena&quot;">​</a></h4><p>The <strong>AI Arena</strong> is the entry point within DGrid where all AI reward and evaluation activities take place. It hosts:</p><ul><li>​<strong>AI Battle</strong>​: daily missions where users compare AI answers</li><li>​<strong>Points and Rewards</strong>​: tracking of earned points, redemptions, and leaderboard rank</li></ul><p>Access AI Arena from the DGrid interface or directly at: <a href="https://dgrid.ai/arena" target="_blank" rel="noreferrer"><code>https://dgrid.ai/arena</code></a></p><h4 id="ai-battle" tabindex="-1">AI Battle <a class="header-anchor" href="#ai-battle" aria-label="Permalink to &quot;AI Battle&quot;">​</a></h4><p><strong>AI Battle</strong> is the main interaction flow in DGrid AI Arena. Users:</p><ul><li>Receive a random question or prompt</li><li>See <strong>two anonymous AI model responses</strong></li><li>Choose which answer they think is better</li></ul><p>Each decision yields points and feeds into DGrid’s model evaluation and training pipeline.</p><h4 id="points" tabindex="-1">Points <a class="header-anchor" href="#points" aria-label="Permalink to &quot;Points&quot;">​</a></h4><p><strong>Points</strong> are the internal metric of contribution in DGrid AI Arena. They:</p><ul><li>Are earned by: <ul><li>Completing daily AI Battle missions</li><li>Referring new users</li></ul></li><li>Are used for: <ul><li>Direct conversion into USDT</li><li>Determining share of the weekly leaderboard prize pool</li></ul></li></ul><h4 id="rewards-usdt-weekly-pool" tabindex="-1">Rewards (USDT &amp; Weekly Pool) <a class="header-anchor" href="#rewards-usdt-weekly-pool" aria-label="Permalink to &quot;Rewards (USDT &amp; Weekly Pool)&quot;">​</a></h4><p>DGrid AI Arena rewards participation with ​<strong>real, on‑chain value</strong>​:</p><ul><li><strong>Direct USDT redemption</strong> based on accumulated points</li><li><strong>Weekly leaderboard rewards</strong> from a shared <strong>USD 300 prize pool</strong></li></ul><h2 id="how-ai-battle-works" tabindex="-1">How AI Battle Works <a class="header-anchor" href="#how-ai-battle-works" aria-label="Permalink to &quot;How AI Battle Works&quot;">​</a></h2><h3 id="daily-missions" tabindex="-1">Daily Missions <a class="header-anchor" href="#daily-missions" aria-label="Permalink to &quot;Daily Missions&quot;">​</a></h3><ul><li>Each user can complete up to ​<strong>5 Daily Missions per day</strong>​.</li><li>Every mission is designed to be ​<strong>quick and intuitive</strong>​, taking only a short moment.</li><li>Missions reset daily, encouraging consistent participation over time.</li></ul><h3 id="mission-flow" tabindex="-1">Mission Flow <a class="header-anchor" href="#mission-flow" aria-label="Permalink to &quot;Mission Flow&quot;">​</a></h3><p>For each mission:</p><ol><li><strong>Prompt Display</strong></li></ol><ul><li>The user is shown a ​<em>random question or prompt</em>​.</li></ul><ol start="2"><li><strong>Two Anonymous AI Responses</strong></li></ol><ul><li>The prompt is followed by ​<strong>two AI answers</strong>​, each from potentially different models.</li><li>The models are anonymous; only the content of the answers is visible.</li></ul><ol start="3"><li><strong>User Choice</strong></li></ol><ul><li>The user reads both answers carefully.</li><li>The user selects the answer they believe: <ul><li>Better fits the prompt</li><li>Better matches their expectations or needs</li></ul></li></ul><ol start="4"><li><strong>Points Awarded Based on Consensus</strong></li></ol><ul><li>After enough users have voted, a <strong>community majority</strong> emerges for that mission.</li><li>The user’s reward depends on whether their choice aligns with this majority (details in the next section).</li></ul><h3 id="role-in-model-training-and-evaluation" tabindex="-1">Role in Model Training and Evaluation <a class="header-anchor" href="#role-in-model-training-and-evaluation" aria-label="Permalink to &quot;Role in Model Training and Evaluation&quot;">​</a></h3><p>Every vote in AI Battle is a <strong>data point</strong> for DGrid’s AI network. DGrid aggregates these user choices to:</p><ul><li><strong>Evaluate model performance</strong>: Identify which models consistently produce preferred answers</li><li><strong>Understand user preferences</strong>: What users value in terms of clarity, helpfulness, safety, and relevance</li><li><strong>Guide model evolution</strong>: Prioritize better-performing models; Inform fine-tuning strategies and deployment decisions</li></ul><p>At scale, thousands of daily micro-decisions across many users form a powerful ​<strong>human feedback signal</strong>​, enabling DGrid to:</p><ul><li>Build a more <strong>reliable, human‑aligned AI LLM network</strong></li><li>Improve robustness across diverse question types</li><li>Move beyond static benchmarks to <strong>continuous, live evaluation</strong></li></ul><h2 id="points-system" tabindex="-1">Points System <a class="header-anchor" href="#points-system" aria-label="Permalink to &quot;Points System&quot;">​</a></h2><h3 id="how-points-are-earned" tabindex="-1">How Points Are Earned <a class="header-anchor" href="#how-points-are-earned" aria-label="Permalink to &quot;How Points Are Earned&quot;">​</a></h3><p>There are two primary ways to earn points in DGrid AI Arena:</p><ol><li><strong>Daily Missions in AI Battle</strong></li></ol><ul><li>Each mission awards ​<strong>5–10 points</strong>​: <ul><li><strong>10 points</strong> if your choice matches the <strong>community majority</strong></li><li><strong>5 points</strong> if your choice does <strong>not</strong> match the majority</li></ul></li><li>There is ​<strong>no “wrong” participation</strong>​: <ul><li>Even if you choose differently from the majority, you still earn points</li><li>Every vote is treated as valuable feedback</li></ul></li><li>With ​<strong>up to 5 missions per day</strong>​, users can accumulate points steadily while contributing to model training.</li></ul><ol start="2"><li><strong>Referral Points</strong></li></ol><ul><li>Users can invite others to join DGrid AI Arena.</li><li>For ​<strong>each valid referred user</strong>​, the referrer earns up to ​<strong>100 points</strong>​.</li><li>Referrals allow users to ​<strong>scale rewards via community growth</strong>​, not just their own activity.</li></ul><h3 id="how-points-are-used" tabindex="-1">How Points Are Used <a class="header-anchor" href="#how-points-are-used" aria-label="Permalink to &quot;How Points Are Used&quot;">​</a></h3><p>Your <strong>total points</strong> serve two key purposes:</p><ul><li><strong>Direct USDT redemptions</strong></li><li><strong>Leaderboard ranking and share of the weekly prize pool</strong></li></ul><p>The more points you earn through missions and referrals:</p><ul><li>The more USDT you can redeem</li><li>The higher your relative position on the weekly leaderboard</li><li>The greater your share of the weekly reward pool</li></ul><h2 id="rewards-model" tabindex="-1">Rewards Model <a class="header-anchor" href="#rewards-model" aria-label="Permalink to &quot;Rewards Model&quot;">​</a></h2><h3 id="direct-redemption-points-→-usdt" tabindex="-1">Direct Redemption: Points → USDT <a class="header-anchor" href="#direct-redemption-points-→-usdt" aria-label="Permalink to &quot;Direct Redemption: Points → USDT&quot;">​</a></h3><p>Users can convert their points directly into <strong>USDT</strong> at a fixed rate:</p><ul><li>​<strong>Conversion rate</strong>​: <ul><li>`1,000 Points = 1 USDT`</li></ul></li><li>​<strong>Minimum redemption amount</strong>​: <ul><li><strong>1,000 Points</strong> (equivalent to 1 USDT)</li></ul></li><li>​<strong>Redemption outcome</strong>​: <ul><li>Once redeemed, USDT is transferred <strong>directly to the user’s wallet</strong> connected to DGrid.</li></ul></li></ul><p>This provides a <strong>clear and transparent</strong> relationship between effort and earnings:</p><blockquote><p>More missions completed + more referrals → More points → More USDT in your wallet.</p></blockquote><h3 id="weekly-leaderboard-competitive-rewards" tabindex="-1">Weekly Leaderboard: Competitive Rewards <a class="header-anchor" href="#weekly-leaderboard-competitive-rewards" aria-label="Permalink to &quot;Weekly Leaderboard: Competitive Rewards&quot;">​</a></h3><p>Beyond direct redemptions, DGrid AI Arena includes a <strong>Weekly Leaderboard</strong> designed to reward the most active and impactful participants.</p><ul><li>​<strong>Weekly Prize Pool</strong>​: <ul><li><strong>USD 300</strong> per week</li></ul></li><li>​<strong>Distribution Mechanism</strong>​: <ul><li>Top participants share the <strong>USD 300</strong> pool</li><li>Rewards are ​<strong>proportional to weekly points earned</strong>​: <ul><li>The more points you earn in that week</li><li>The larger your share of the <strong>USD 300</strong> pool</li></ul></li></ul></li></ul><h3 id="reward-structure-summary" tabindex="-1">Reward Structure Summary <a class="header-anchor" href="#reward-structure-summary" aria-label="Permalink to &quot;Reward Structure Summary&quot;">​</a></h3><ul><li><strong>Casual users</strong><ul><li>Earn via consistent daily missions</li><li>Can convert points into USDT over time</li></ul></li><li><strong>Power users &amp; top contributors</strong><ul><li>Benefit from both: <ul><li>Direct USDT redemption, and</li><li>Additional income from leaderboard rewards</li></ul></li></ul></li></ul><p>This <strong>dual reward mechanism</strong> ensures that all participation is recognized, while also ​<strong>incentivizing sustained and high-impact engagement</strong>​.</p><h2 id="getting-started-with-dgrid-ai-arena" tabindex="-1">Getting Started with DGrid AI Arena <a class="header-anchor" href="#getting-started-with-dgrid-ai-arena" aria-label="Permalink to &quot;Getting Started with DGrid AI Arena&quot;">​</a></h2><h3 id="step-1-access-ai-arena" tabindex="-1">Step 1: Access AI Arena <a class="header-anchor" href="#step-1-access-ai-arena" aria-label="Permalink to &quot;Step 1: Access AI Arena&quot;">​</a></h3><p>Navigate to the ​<strong>AI Arena</strong>​: <a href="https://dgrid.ai/arena" target="_blank" rel="noreferrer"><code>https://dgrid.ai/arena</code></a>.</p><p>Once there:</p><ul><li><strong>Connect your wallet</strong></li><li><strong>Activate your Arena access</strong></li></ul><p><img src="'+r+'" alt=""></p><h3 id="step-2-start-ai-battle" tabindex="-1">Step 2: Start AI Battle <a class="header-anchor" href="#step-2-start-ai-battle" aria-label="Permalink to &quot;Step 2: Start AI Battle&quot;">​</a></h3><p>Click <strong>“Start AI Battle”</strong>. After mission begins: You’ll see a <strong>question/prompt</strong> and ​<strong>two anonymous AI responses</strong>​. Read both answers carefully and select the one you think is better. For each completed mission:</p><ul><li>You earn ​<strong>5–10 points</strong>​, depending on alignment with community consensus.</li><li>You can complete <strong>up to 5 missions</strong> per day.</li></ul><p><img src="'+t+'" alt=""></p><h3 id="step-3-repeat-daily" tabindex="-1">Step 3: Repeat Daily <a class="header-anchor" href="#step-3-repeat-daily" aria-label="Permalink to &quot;Step 3: Repeat Daily&quot;">​</a></h3><p>Return every day to:</p><ul><li>Complete your <strong>5 daily missions</strong></li><li>Accumulate more points</li><li>Continuously contribute to training and improving DGrid AI</li></ul><p><img src="'+o+'" alt=""></p><h3 id="step-4-invite-friends-referrals" tabindex="-1">Step 4: Invite Friends (Referrals) <a class="header-anchor" href="#step-4-invite-friends-referrals" aria-label="Permalink to &quot;Step 4: Invite Friends (Referrals)&quot;">​</a></h3><p>Share DGrid AI Arena with your network using your referral mechanism in the DGrid UI. For each ​<strong>valid referred user</strong>​, you receive up to ​<strong>100 points</strong>​.</p><p>Referrals help:</p><ul><li>Grow the <strong>DGrid community</strong></li><li>Increase the <strong>volume and diversity of AI Battle feedback</strong></li><li>Boost your own points and rewards</li></ul><h3 id="step-5-redeem-points-track-leaderboard-rank" tabindex="-1">Step 5: Redeem Points &amp; Track Leaderboard Rank <a class="header-anchor" href="#step-5-redeem-points-track-leaderboard-rank" aria-label="Permalink to &quot;Step 5: Redeem Points &amp; Track Leaderboard Rank&quot;">​</a></h3><p>Monitor your <strong>total points</strong> in the DGrid interface. When you reach at least ​<strong>1,000 points</strong>​, you can: Redeem them for <strong>USDT</strong> at the `1,000 : 1 USDT` rate. Check the <strong>Weekly Leaderboard</strong> to see:</p><ul><li>Your ranking relative to other participants</li><li>Your potential share of the <strong>USD 300</strong> weekly prize pool</li></ul><h2 id="why-dgrid-ai-arena-matters" tabindex="-1">Why DGrid AI Arena Matters <a class="header-anchor" href="#why-dgrid-ai-arena-matters" aria-label="Permalink to &quot;Why DGrid AI Arena Matters&quot;">​</a></h2><p>DGrid AI Arena is a <strong>collaborative intelligence layer</strong> built on top of DGrid’s AI infrastructure. It is designed to make the DGrid AI network:</p><ul><li><strong>More aligned</strong> with real user expectations</li><li><strong>More robust</strong> across many question and content types</li><li>​<strong>Continuously improving</strong>​, driven by live, real-world feedback</li></ul><h3 id="human-judgment-at-scale" tabindex="-1">Human Judgment at Scale <a class="header-anchor" href="#human-judgment-at-scale" aria-label="Permalink to &quot;Human Judgment at Scale&quot;">​</a></h3><p>By combining:</p><ul><li>Human judgment from thousands of AI Battles</li><li>Community-driven evaluation of model quality</li><li>A transparent, on‑chain reward mechanism tied to USDT</li></ul><p>DGrid can:</p><ul><li>Determine which models to prioritize and deploy</li><li>Learn what users consider: Clear, Helpful, Safe and Relevant</li><li>Decide how and when to roll out new capabilities across the ecosystem</li></ul><p>Every point earned is more than just a number — it is a <strong>signal</strong> that helps decide:</p><ul><li>Which models “win” in head‑to‑head comparisons</li><li>How models should be <strong>fine‑tuned</strong></li><li>Which behaviors should be <strong>reinforced or discouraged</strong></li></ul><p>In this way, ​<strong>every user choice becomes a vote for better AI</strong>​.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h4 id="is-there-a-wrong-choice-in-ai-battle" tabindex="-1">Is there a “wrong” choice in AI Battle? <a class="header-anchor" href="#is-there-a-wrong-choice-in-ai-battle" aria-label="Permalink to &quot;Is there a “wrong” choice in AI Battle?&quot;">​</a></h4><p>No. There is ​<strong>no wrong participation</strong>​.</p><ul><li>If your choice matches the ​<strong>community majority</strong>​, you earn ​<strong>10 points</strong>​.</li><li>If your choice does <strong>not</strong> match the majority, you still earn ​<strong>5 points</strong>​.</li></ul><p>Every decision is considered valuable signal for model evaluation.</p><h4 id="how-many-missions-can-i-complete-each-day" tabindex="-1">How many missions can I complete each day? <a class="header-anchor" href="#how-many-missions-can-i-complete-each-day" aria-label="Permalink to &quot;How many missions can I complete each day?&quot;">​</a></h4><p>You can complete up to <strong>5 Daily Missions</strong> in AI Battle per day.</p><h4 id="how-do-i-earn-referral-points" tabindex="-1">How do I earn referral points? <a class="header-anchor" href="#how-do-i-earn-referral-points" aria-label="Permalink to &quot;How do I earn referral points?&quot;">​</a></h4><p>Invite others to join DGrid AI Arena using the referral mechanism in the DGrid interface. For each ​<strong>valid referred user</strong>​, you receive up to ​<strong>100 points</strong>​.</p><h4 id="how-are-my-points-converted-to-usdt" tabindex="-1">How are my points converted to USDT? <a class="header-anchor" href="#how-are-my-points-converted-to-usdt" aria-label="Permalink to &quot;How are my points converted to USDT?&quot;">​</a></h4><ul><li>Points convert at a fixed rate of <code>1,000 Points = 1 USDT</code>.</li><li>You need a minimum of <strong>1,000 points</strong> to redeem.</li><li>Once redeemed, ​<strong>USDT is sent directly to your connected wallet</strong>​.</li></ul><h4 id="how-does-the-weekly-leaderboard-work" tabindex="-1">How does the weekly leaderboard work? <a class="header-anchor" href="#how-does-the-weekly-leaderboard-work" aria-label="Permalink to &quot;How does the weekly leaderboard work?&quot;">​</a></h4><ul><li>Each week, DGrid allocates a ​<strong>USD 300 prize pool</strong>​.</li><li>Users are ranked based on ​<strong>points earned during that week</strong>​.</li><li>The prize pool is split ​<strong>proportionally</strong>​: More weekly points → larger share of the ​<strong>USD 300</strong>​.</li></ul><h4 id="how-does-my-participation-improve-dgrid-ai" tabindex="-1">How does my participation improve DGrid AI? <a class="header-anchor" href="#how-does-my-participation-improve-dgrid-ai" aria-label="Permalink to &quot;How does my participation improve DGrid AI?&quot;">​</a></h4><p>Your votes:</p><ul><li>Tell DGrid which AI responses users prefer</li><li>Help identify which models perform best in real usage</li><li>Provide ongoing feedback that informs: Model selection; Fine-tuning strategies; Safety and quality improvements</li></ul>',111)]))}const f=i(l,[["render",d]]);export{w as __pageData,f as default};
